def solve(arg1: dict) -> dict:
    member_id = arg1.get('member_id')
    challenge_id = arg1.get('challenge_id')
    submitted = arg1.get('submitted', False)

    # Simulated data for testing purposes
    challenge_data = {
        '67890': {
            'is_closed': False,
            'submissions': ['submission1', 'submission2', 'submission3'],
            'valid_members': ['12345']
        }
    }

    challenge = challenge_data.get(challenge_id)

    if not challenge:
        return {'can_download': False}

    if challenge['is_closed'] and member_id in challenge['valid_members']:
        return {'can_download': True}

    if not submitted:
        return {'can_download': False}

    if member_id in challenge['valid_members']:
        return {
            'can_download': True,
            'downloadable_submissions': challenge['submissions']
        }

    return {'can_download': False}
